// /scoring.js
// This module encapsulates all logic for the new, holistic Proficiency Dashboard.

// --- STATE ---
let proficiencyLog = [];

export function initScoring() {
    const logJSON = localStorage.getItem('wordwiseProficiencyLog');
    proficiencyLog = logJSON ? JSON.parse(logJSON) : [];
}

export function getProficiencyLog() {
    return proficiencyLog;
}

export function setProficiencyLog(newLog) {
    proficiencyLog = newLog;
    localStorage.setItem('wordwiseProficiencyLog', JSON.stringify(proficiencyLog));
}

export function logProficiency(decks, quizHistory, force = false) {
    if (!force) {
        const lastLog = proficiencyLog[proficiencyLog.length - 1];
        const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000;
        if (lastLog && (Date.now() - lastLog.timestamp < TWENTY_FOUR_HOURS_MS)) {
            return; 
        }
    }

    const currentStats = calculateGlobalProficiency(decks, quizHistory);
    proficiencyLog.push({
        timestamp: Date.now(),
        score: currentStats.score
    });
    localStorage.setItem('wordwiseProficiencyLog', JSON.stringify(proficiencyLog));
}

