/**
 * Handles header button clicks for the Deck Viewer.
 * @param {Event} e - The click event.
 * @returns {boolean} True if the event was handled.
 */
export function handleHeaderClick(e) {
    if (e.target.closest('#header-deck-options-btn')) {
        e.preventDefault(); e.stopPropagation();
        const menu = e.target.closest('.options-container').querySelector('.options-menu');
        actions.ui.toggleMenu(menu, 'options');
        return true;
    }
    if (e.target.closest('#header-deck-edit-btn')) {
        e.preventDefault(); e.stopPropagation(); actions.ui.closeActiveMenu();
        const currentDeck = currentDeckState.deck;
        // Assume deckManager handles the actual edit modal logic via actions
        if (currentDeck && actions.onEditDeck) actions.onEditDeck(currentDeck);
        return true;
    }
    if (e.target.closest('#header-deck-test-btn')) {
        e.preventDefault(); e.stopPropagation(); actions.ui.closeActiveMenu();
        const currentDeck = currentDeckState.deck;
        if (currentDeck && actions.onStartQuiz) actions.onStartQuiz(currentDeck);
        return true;
    }
    if (e.target.closest('#header-deck-export-btn')) {
        e.preventDefault(); e.stopPropagation(); actions.ui.closeActiveMenu();
        const currentDeck = currentDeckState.deck;
        if (currentDeck && actions.onExportDeck) actions.onExportDeck(currentDeck);
        return true;
    }
    if (e.target.closest('#header-deck-log-btn')) {
         e.preventDefault(); e.stopPropagation(); actions.ui.closeActiveMenu();
        const currentDeck = currentDeckState.deck;
        if (currentDeck && currentDeck.isSpecial && actions.onViewWotdLog) {
            actions.onViewWotdLog(currentDeck);
        }
        return true;
    }
    return false;
}

/**
 * Exposes the currently viewed word for external modules.
 * @returns {object|null} The current word object.
 */
export function getCurrentWord() {
    return currentDeckState.currentWord;
}

