// /stateManager.js
// Centralizes Core Data State (Decks, Folders, Credentials) and Persistence.

// --- State Variables ---
let decks = [];
let folders = [];
let supabaseUrl = '';
let supabaseAnonKey = '';

// --- Constants ---
const STORAGE_KEYS = {
    DECKS: 'wordwiseDecks',
    FOLDERS: 'wordwiseFolders',
    SRS_MIGRATED: 'wordwiseSrsMigrated',
    SUPABASE_URL: 'wordwiseSupabaseUrl',
    SUPABASE_KEY: 'wordwiseSupabaseAnonKey'
};

/**
 * Initializes the state by loading from LocalStorage and performing migrations.
 */
export function initStateManager() {
    loadCredentials();
    folders = loadFoldersFromStorage();
    decks = loadDecksFromStorage();

    // Run one-time migrations if needed
    if (!localStorage.getItem(STORAGE_KEYS.SRS_MIGRATED)) {
        migrateSrsData();
        localStorage.setItem(STORAGE_KEYS.SRS_MIGRATED, 'true');
        saveDecks();
    }
    console.log("State Manager initialized.");
}

// --- Getters ---
export function getDecks() { return decks; }
export function getFolders() { return folders; }
export function getCredentials() { return { supabaseUrl, supabaseAnonKey }; }

// --- Setters / Modifiers ---
export function addDeck(newDeck) {
    decks.push(newDeck);
    saveDecks();
}

export function updateDeck(updatedDeck) {
    const index = decks.findIndex(d => d.id === updatedDeck.id);
    if (index > -1) {
        decks[index] = updatedDeck;
        saveDecks();
    }
}

export function deleteDeck(deckId) {
    decks = decks.filter(d => d.id !== deckId);
    saveDecks();
}

export function updateFolders(newFolders) {
    folders = newFolders;
    saveFolders();
}

// --- Persistence Logic (Migrated from deckManager.js) ---

export function saveDecks() {
    localStorage.setItem(STORAGE_KEYS.DECKS, JSON.stringify(decks));
}

export function saveFolders() {
    localStorage.setItem(STORAGE_KEYS.FOLDERS, JSON.stringify(folders));
}

export function saveCredential(key, type) {
    if (type === 'SupabaseUrl') {
        supabaseUrl = key;
        localStorage.setItem(STORAGE_KEYS.SUPABASE_URL, key);
    } else if (type === 'SupabaseAnonKey') {
        supabaseAnonKey = key;
        localStorage.setItem(STORAGE_KEYS.SUPABASE_KEY, key);
    }
}

function loadCredentials() {
    supabaseUrl = localStorage.getItem(STORAGE_KEYS.SUPABASE_URL) || '';
    supabaseAnonKey = localStorage.getItem(STORAGE_KEYS.SUPABASE_KEY) || '';
}

function loadFoldersFromStorage() {
    const foldersJSON = localStorage.getItem(STORAGE_KEYS.FOLDERS);
    let loadedFolders = foldersJSON ? JSON.parse(foldersJSON) : [];
    let needsSave = false;

    // Migration: Add parentId to existing folders
    loadedFolders.forEach(folder => {
        if (!folder.hasOwnProperty('parentId')) {
            folder.parentId = null;
            needsSave = true;
        }
    });

    if (loadedFolders.length === 0) {
        loadedFolders = [{ id: 'f1', name: 'English', color: '#3b82f6', parentId: null }];
        needsSave = true;
    }

    if (needsSave) localStorage.setItem(STORAGE_KEYS.FOLDERS, JSON.stringify(loadedFolders));
    return loadedFolders;
}

function loadDecksFromStorage() {
    const decksJSON = localStorage.getItem(STORAGE_KEYS.DECKS);
    let loadedDecks = decksJSON ? JSON.parse(decksJSON) : [];
    let needsSave = false;

    // WotD Deck Check
    const WOTD_DECK_ID = 'word_of_the_day_deck';
    const defaultWotdImage = 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?q=80&w=2070&auto=format&fit=crop';
    let wotdDeck = loadedDecks.find(d => d.id === WOTD_DECK_ID);

    if (!wotdDeck) {
        wotdDeck = {
            id: WOTD_DECK_ID,
            title: "Word of the Day",
            description: "A collection of daily words from Merriam Webster.",
            words: [],
            type: 'Vocabulary',
            isSpecial: true,
            imageUrl: defaultWotdImage,
            createdAt: new Date().toISOString()
        };
        loadedDecks.unshift(wotdDeck);
        needsSave = true;
    } else if (!wotdDeck.imageUrl) {
        wotdDeck.imageUrl = defaultWotdImage;
        needsSave = true;
    }

    // Migration Logic
    loadedDecks.forEach(deck => {
        if (!deck.hasOwnProperty('folderId')) {
            deck.folderId = null;
            needsSave = true;
        }
        if (deck.words && deck.words.length > 0) {
            let deckWasMigrated = false;
            deck.words = deck.words.map(word => {
                if (typeof word === 'string' || !word.hasOwnProperty('definitions')) {
                    deckWasMigrated = true;
                    return {
                        text: typeof word === 'string' ? word : word.text,
                        masteryLevel: word.masteryLevel || 0,
                        lastSeen: word.lastSeen || null,
                        imageUrl: null,
                        isImageProvisional: true,
                        definitions: { flashcard: null, detailed: null, gemini: null, merriamWebster: null }
                    };
                }
                return word;
            });
            if (deckWasMigrated) needsSave = true;
        }
    });

    if (needsSave) localStorage.setItem(STORAGE_KEYS.DECKS, JSON.stringify(loadedDecks));
    return loadedDecks;
}

function migrateSrsData() {
    console.log("Migrating SRS data...");
    const oldIntervals = [1, 3, 7, 14, 30, 90, 180];
    let needsSave = false;

    decks.forEach(deck => {
        deck.words.forEach(word => {
            if (word.hasOwnProperty('masteryLevel')) {
                needsSave = true;
                const level = word.masteryLevel || 0;
                word.interval = level > 0 ? oldIntervals[Math.min(level - 1, oldIntervals.length - 1)] : 0;
                word.factor = 2.5;
                delete word.masteryLevel;
            }
        });
    });

    if (needsSave) saveDecks();
}

