            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ action: 'get_book_compressed', book_path: bookPath })
        });
        if (!res.ok) throw new Error("Load failed");

        let html = await res.text();

        // Force fully zoomed-out view by setting a fixed wide viewport.
        // This prevents the "zoomed in" mobile view for absolute-positioned PDF content
