        html = html.replace(/<meta\s+name=["']viewport["'][^>]*>/gi, "");
        const wideViewport = '<meta name="viewport" content="width=1200, user-scalable=yes">';

        if (html.includes("<head>")) {
            html = html.replace("<head>", "<head>" + wideViewport);
        } else {
            html = "<!DOCTYPE html><html><head>" + wideViewport + "</head><body>" + html + "</body></html>";
        }

        const blob = new Blob([html], { type: 'text/html' });
        const url = URL.createObjectURL(blob);
        setActiveBookContent(url);
        setReaderOpen(true);
    } catch (e) {
        console.error("Failed to load book", e);
    } finally {
        setLoadingBook(false);
    }
};

