package com.example.myandroid

import android.content.Context
import android.content.res.ColorStateList
import android.graphics.Canvas
import android.graphics.Color
import android.graphics.Paint
import android.graphics.RectF
import android.graphics.drawable.GradientDrawable
import android.hardware.Sensor
import android.hardware.SensorManager
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.Build
import android.os.Bundle
import android.util.DisplayMetrics
import android.view.Gravity
import android.view.View
import android.view.ViewGroup
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.ProgressBar
import android.widget.ScrollView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import java.util.Date
import java.util.Locale

class MainActivity : AppCompatActivity() {

    // --- THEME COLORS ---
    private val COL_BG = 0xFF050505.toInt()
    private val COL_GLASS = 0x1AFFFFFF.toInt()
    private val COL_ACCENT_CYAN = 0xFF00F2FF.toInt()
    private val COL_ACCENT_PURPLE = 0xFFBD00FF.toInt()
    private val COL_ACCENT_GREEN = 0xFF00FF9D.toInt()
    private val COL_TEXT_MUTED = 0xFF8B9BB4.toInt()

    // --- VIEW MANAGEMENT ---
    private lateinit var contentContainer: FrameLayout
    private val views = mutableMapOf<String, View>()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // 1. IMMERSIVE THEME
        window.statusBarColor = COL_BG
        window.navigationBarColor = 0xFF141414.toInt()
        supportActionBar?.hide()

        // 2. ROOT LAYOUT
        val root = FrameLayout(this).apply {
            setBackgroundColor(COL_BG)
        }

        // 3. SCROLLABLE CONTENT AREA
        contentContainer = FrameLayout(this).apply {
            setPadding(0, 180, 0, 200) // Space for Header & Nav
        }
        root.addView(contentContainer)

        // 4. ADD HEADER
        root.addView(createHeader())

        // 5. INITIALIZE SCREENS
        setupPages()

        // 6. ADD BOTTOM NAVIGATION
        root.addView(createBottomNav())

        setContentView(root)

        // 7. LAUNCH HOME
        switchView("DASH")
    }

    private fun setupPages() {
        views["DASH"] = createDashboardView().also { contentContainer.addView(it); it.visibility = View.GONE }
        views["SPECS"] = createSpecsView().also { contentContainer.addView(it); it.visibility = View.GONE }
        views["NET"] = createNetView().also { contentContainer.addView(it); it.visibility = View.GONE }
        views["TOOLS"] = createToolsView().also { contentContainer.addView(it); it.visibility = View.GONE }
    }

    private fun switchView(key: String) {
        views.forEach { (k, v) ->
            v.visibility = if (k == key) View.VISIBLE else View.GONE
        }
    }

    // --- UI BUILDERS ---

    private fun createHeader(): View {
        return LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(60, 60, 60, 20)
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT)

            addView(TextView(context).apply {
                text = "MY ANDROID"
                textSize = 24f
                setTextColor(Color.WHITE)
                setTypeface(null, android.graphics.Typeface.BOLD)
            })
            addView(TextView(context).apply {
                text = Build.MODEL.uppercase()
                textSize = 12f
                setTextColor(COL_ACCENT_CYAN)
                setPadding(0, 10, 0, 0)
            })
        }
    }

    private fun createBottomNav(): View {
        val nav = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            gravity = Gravity.CENTER
            background = getGlassDrawable(50f, 0xCC141414.toInt())
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 180).apply {
                gravity = Gravity.BOTTOM
                setMargins(40, 0, 40, 40)
            }
        }

        val tabs = listOf("DASH" to "📊", "SPECS" to "⚙️", "NET" to "🌍", "TOOLS" to "🧩")
        tabs.forEach { (key, icon) ->
            val btn = LinearLayout(this).apply {
                orientation = LinearLayout.VERTICAL
                gravity = Gravity.CENTER
                layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.MATCH_PARENT, 1f)
                setOnClickListener { switchView(key) }

                addView(TextView(context).apply {
                    text = icon
                    textSize = 22f
                    gravity = Gravity.CENTER
                })
                addView(TextView(context).apply {
                    text = key
                    textSize = 10f
                    setTextColor(Color.LTGRAY)
                    gravity = Gravity.CENTER
                })
            }
            nav.addView(btn)
        }
        return nav
    }

    // --- PAGE GENERATORS ---

    private fun createDashboardView(): View = ScrollView(this).apply {
        val layout = LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 0, 40, 0)
        }

        // Row of Gauges
        val row = LinearLayout(context).apply {
            orientation = LinearLayout.HORIZONTAL
            weightSum = 2f
        }

        val ramInfo = getRamInfo(context)
        row.addView(createGaugeCard("RAM", ramInfo.first, ramInfo.second, COL_ACCENT_PURPLE))

        val battInfo = getBatterySimple(context)
        row.addView(createGaugeCard("POWER", battInfo.first, battInfo.second, COL_ACCENT_GREEN))

        layout.addView(row)

        // Storage Bar
        val storage = getStorageSimple(context)
        layout.addView(createGlassCard("STORAGE", storage, true))

        // System Info
        layout.addView(createGlassCard("SYSTEM", "Android ${Build.VERSION.RELEASE}\nSDK ${Build.VERSION.SDK_INT}"))

        addView(layout)
    }

    private fun createSpecsView(): View = ScrollView(this).apply {
        val layout = LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 0, 40, 0)
        }

        layout.addView(createSectionTitle("PROCESSOR"))
        val hw = getHardwareInfo(context)
        layout.addView(createGlassCard("CPU", "${hw["CPU CORES"]}\n${hw["SUPPORTED ABIS"]}"))
        layout.addView(createGlassCard("DETAILS", "${hw["BOARD"]}\n${hw["MANUFACTURER"]}"))

        layout.addView(createSectionTitle("DISPLAY"))
        val disp = getDisplayInfo(context)
        disp.forEach { (k, v) -> layout.addView(createGlassCard(k, v)) }

        layout.addView(createSectionTitle("OS DEEP DIVE"))
        val os = getOsInfo()
        os.forEach { (k, v) -> layout.addView(createGlassCard(k, v)) }

        addView(layout)
    }

    private fun createNetView(): View = ScrollView(this).apply {
        val layout = LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 0, 40, 0)
        }

        val net = getNetworkInfo(context)
        val status = net["STATUS"] ?: "Unknown"
        val color = if (status == "Connected") COL_ACCENT_GREEN else Color.RED

        // Manually creating the status card to colorize the value
        val statusCard = createGlassCard("STATUS", status)
        ((statusCard as LinearLayout).getChildAt(1) as TextView).setTextColor(color)
        layout.addView(statusCard)

        net.filter { it.key != "STATUS" }.forEach { (k, v) ->
            layout.addView(createGlassCard(k, v))
        }
        addView(layout)
    }

    private fun createToolsView(): View = ScrollView(this).apply {
        val layout = LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 0, 40, 0)
        }

        layout.addView(createSectionTitle("SYSTEM FEATURES"))
        val feats = getFeatureInfo(context)
        feats.forEach { (k, v) -> layout.addView(createGlassCard(k, v)) }

        layout.addView(createSectionTitle("LIVE SENSORS"))
        val sens = getSensorInfo(context)
        sens.forEach { (k, v) ->
            if (k.startsWith("#")) layout.addView(createGlassCard(k.substring(3), v))
            else layout.addView(createGlassCard(k, v))
        }
        addView(layout)
    }

    // --- HELPER FUNCTIONS ---

    private fun createSectionTitle(title: String): View {
        return TextView(context).apply {
            text = title
            textSize = 12f
            setTextColor(COL_TEXT_MUTED)
            setPadding(10, 40, 0, 10)
            setTypeface(null, android.graphics.Typeface.BOLD)
        }
    }

    private fun createGlassCard(title: String, value: String, isProgress: Boolean = false): View {
        return LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(40, 40, 40, 40)
            background = getGlassDrawable()
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT).apply {
                setMargins(0, 0, 0, 30)
            }

            addView(TextView(context).apply {
                text = title
                textSize = 10f
                setTextColor(COL_TEXT_MUTED)
                letterSpacing = 0.15f
            })

            if (isProgress) {
                addView(ProgressBar(context, null, android.R.attr.progressBarStyleHorizontal).apply {
                    progress = 75
                    scaleY = 2f
                    setPadding(0, 20, 0, 0)
                    progressTintList = ColorStateList.valueOf(COL_ACCENT_CYAN)
                })
                addView(TextView(context).apply {
                    text = value
                    textSize = 12f
                    setTextColor(Color.WHITE)
                    setPadding(0, 10, 0, 0)
                })
            } else {
                addView(TextView(context).apply {
                    text = value
                    textSize = 16f
                    setTextColor(Color.WHITE)
                    setTypeface(null, android.graphics.Typeface.BOLD)
                    setPadding(0, 15, 0, 0)
                })
            }
        }
    }

    private fun createGaugeCard(title: String, valueStr: String, pct: Int, color: Int): View {
        return LinearLayout(context).apply {
            orientation = LinearLayout.VERTICAL
            gravity = Gravity.CENTER
            background = getGlassDrawable()
            layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply {
                setMargins(10, 0, 10, 30)
            }
            setPadding(30, 40, 30, 40)

            addView(TextView(context).apply {
                text = title
                textSize = 10f
                setTextColor(COL_TEXT_MUTED)
            })

            addView(GaugeView(context, color, pct).apply {
                layoutParams = LinearLayout.LayoutParams(150, 150).apply {
                    setMargins(0, 30, 0, 20)
                }
            })

            addView(TextView(context).apply {
                text = valueStr
                textSize = 14f
                setTextColor(Color.WHITE)
                setTypeface(null, android.graphics.Typeface.BOLD)
            })
        }
    }

    private fun getGlassDrawable(radius: Float = 30f, bgColor: Int = COL_GLASS): GradientDrawable {
        return GradientDrawable().apply {
            color = ColorStateList.valueOf(bgColor)
            cornerRadius = radius
            setStroke(2, 0x1AFFFFFF.toInt())
        }
    }

    // --- CUSTOM GAUGE VIEW ---
    class GaugeView(context: Context, val color: Int, val pct: Int) : View(context) {
        private val paint = Paint(Paint.ANTI_ALIAS_FLAG)
        private val rect = RectF()

        override fun onDraw(canvas: Canvas) {
            super.onDraw(canvas)
            val stroke = 15f
            val s = width.coerceAtMost(height).toFloat() - stroke
            rect.set(stroke / 2, stroke / 2, s, s)

            // Background Ring
            paint.style = Paint.Style.STROKE
            paint.strokeWidth = stroke
            paint.color = 0x33FFFFFF.toInt()
            canvas.drawArc(rect, 0f, 360f, false, paint)

            // Progress Ring
            paint.color = color
            paint.strokeCap = Paint.Cap.ROUND
            canvas.drawArc(rect, -90f, (3.6f * pct), false, paint)
        }
    }

    // --- DATA LOGIC ---

    private fun getRamInfo(ctx: Context): Pair<String, Int> {
        val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
        val memInfo = android.app.ActivityManager.MemoryInfo()
        actManager.getMemoryInfo(memInfo)
        val total = memInfo.totalMem / (1024 * 1024)
        val avail = memInfo.availMem / (1024 * 1024)
        val used = total - avail
        val pct = if (total > 0) ((used.toFloat() / total.toFloat()) * 100).toInt() else 0
        return Pair("$used / $total MB", pct)
    }

    private fun getBatterySimple(ctx: Context): Pair<String, Int> {
        val batt = ctx.registerReceiver(null, android.content.IntentFilter(android.content.Intent.ACTION_BATTERY_CHANGED))
        val level = batt?.getIntExtra(android.os.BatteryManager.EXTRA_LEVEL, 0) ?: 0
        val status = batt?.getIntExtra(android.os.BatteryManager.EXTRA_STATUS, -1) ?: -1
        val isCharging = status == android.os.BatteryManager.BATTERY_STATUS_CHARGING
        return Pair("$level% ${if (isCharging) "⚡" else ""}", level)
    }

    private fun getStorageSimple(ctx: Context): String {
        val dataDir = android.os.Environment.getDataDirectory()
        val stat = android.os.StatFs(dataDir.path)
        val total = (stat.blockCountLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
        val free = (stat.availableBlocksLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
        return "${total - free} GB Used / $total GB Total"
    }

    private fun getOsInfo(): Map<String, String> = mapOf(
        "ANDROID VER" to Build.VERSION.RELEASE,
        "SDK API" to Build.VERSION.SDK_INT.toString(),
        "SECURITY PATCH" to (if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) Build.VERSION.SECURITY_PATCH else "Unknown"),
        "KERNEL" to (System.getProperty("os.version") ?: "Unknown"),
        "BUILD ID" to Build.ID,
        "BOOTLOADER" to Build.BOOTLOADER,
        "FINGERPRINT" to Build.FINGERPRINT.take(20) + "...",
        "BUILD HOST" to Build.HOST,
        "BUILD USER" to Build.USER,
        "BUILD TIME" to java.text.SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.US).format(Date(Build.TIME))
    )

    private fun getHardwareInfo(ctx: Context): Map<String, String> {
        val cores = Runtime.getRuntime().availableProcessors()
        return mapOf(
            "MANUFACTURER" to Build.MANUFACTURER.uppercase(),
            "MODEL" to Build.MODEL,
            "PRODUCT" to Build.PRODUCT,
            "BOARD" to Build.BOARD,
            "CPU CORES" to "$cores Cores",
            "SUPPORTED ABIS" to Build.SUPPORTED_ABIS.joinToString(", ")
        )
    }

    private fun getDisplayInfo(ctx: Context): Map<String, String> {
        val wm = ctx.getSystemService(Context.WINDOW_SERVICE) as android.view.WindowManager
        val dm = DisplayMetrics()
        wm.defaultDisplay.getRealMetrics(dm)
        val refresh = wm.defaultDisplay.refreshRate
        val hdr = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O && wm.defaultDisplay.isHdr) "Yes" else "No"

        return mapOf(
            "RESOLUTION" to "${dm.widthPixels} x ${dm.heightPixels}",
            "DPI (DENSITY)" to "${dm.densityDpi} dpi",
            "REFRESH RATE" to "${refresh.toInt()} Hz",
            "SCALE FACTOR" to "${dm.density}x",
            "HDR SUPPORT" to hdr,
            "ORIENTATION" to if (ctx.resources.configuration.orientation == 1) "Portrait" else "Landscape"
        )
    }

    private fun getNetworkInfo(ctx: Context): Map<String, String> {
        val cm = ctx.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val net = cm.activeNetwork
        val caps = cm.getNetworkCapabilities(net)
        val link = cm.getLinkProperties(net)

        val transport = when {
            caps?.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) == true -> "WiFi"
            caps?.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) == true -> "Cellular Data"
            caps?.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET) == true -> "Ethernet"
            caps?.hasTransport(NetworkCapabilities.TRANSPORT_VPN) == true -> "VPN"
            else -> "No Connection"
        }

        return mapOf(
            "STATUS" to if (net != null) "Connected" else "Disconnected",
            "TYPE" to transport,
            "DOWN SPEED" to "${(caps?.linkDownstreamBandwidthKbps ?: 0) / 1000} Mbps",
            "UP SPEED" to "${(caps?.linkUpstreamBandwidthKbps ?: 0) / 1000} Mbps",
            "METERED" to if (caps?.hasCapability(NetworkCapabilities.NET_CAPABILITY_NOT_METERED) == false) "Yes" else "No",
            "LOCAL IP" to (link?.linkAddresses?.firstOrNull()?.address?.hostAddress ?: "Unknown")
        )
    }

    private fun getSensorInfo(ctx: Context): Map<String, String> {
        val sm = ctx.getSystemService(Context.SENSOR_SERVICE) as SensorManager
        val list = sm.getSensorList(Sensor.TYPE_ALL)
        val map = mutableMapOf<String, String>()

        map["TOTAL SENSORS"] = "${list.size} Found"
        list.take(15).forEachIndexed { i, s ->
            map["#${i + 1} ${s.name}"] = "Vendor: ${s.vendor}\nPower: ${s.power} mA"
        }
        return map
    }

    private fun getFeatureInfo(ctx: Context): Map<String, String> {
        val pm = ctx.packageManager
        return mapOf(
            "NFC" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_NFC).toString(),
            "BLUETOOTH LE" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_BLUETOOTH_LE).toString(),
            "WIFI DIRECT" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_WIFI_DIRECT).toString(),
            "USB HOST" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_USB_HOST).toString(),
            "FINGERPRINT" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_FINGERPRINT).toString(),
            "FACE RECOG" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_FACE).toString(),
            "VR MODE" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_VR_MODE_HIGH_PERFORMANCE).toString(),
            "PIP" to pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_PICTURE_IN_PICTURE).toString()
        )
    }
}

