            padding: 1rem 2rem;
            gap: 1rem;
            height: auto;
        }
        .navigation-magic .icon {
            line-height: normal;
            font-size: 1.2rem;
            transform: none !important;
            width: 24px;
            text-align: center;
        }
        .navigation-magic .text {
            position: static;
            opacity: 1;
            transform: none !important;
            font-size: 1rem;
            font-weight: 500;
        }
        /* Hide mobile indicator, use desktop active state */
        .indicator { display: none; }
        .navigation-magic li.active a {
            background: linear-gradient(90deg, rgba(66, 215, 184, 0.15), transparent);
            border-left: 3px solid var(--accent-teal);
        }
        .navigation-magic li.active .icon {
            color: var(--accent-teal);
        }

        /* Main Content Area */
        .main-content {
            display: flex;
            flex-direction: column;
            background-color: var(--bg-dark);
        }
        .tab-content > .scrollable-content {
            scrollbar-width: thin;
            scrollbar-color: var(--surface-dark) var(--bg-dark);
        }
        .tab-content > .scrollable-content::-webkit-scrollbar {
            display: block;
            width: 8px;
        }
        .tab-content > .scrollable-content::-webkit-scrollbar-track {
            background: var(--bg-dark);
        }
        .tab-content > .scrollable-content::-webkit-scrollbar-thumb {
            background-color: var(--surface-dark);
            border-radius: 4px;
        }

        /* Universal Grid System for Pages */
        .page-content {
            display: grid;
            grid-template-columns: repeat(12, 1fr);
            gap: 1.5rem;
            max-width: 1400px;
            margin: 0 auto;
            width: 100%;
            padding: 2rem;
        }

        /* Home Tab Desktop */
        .hero-wrapper {
            max-width: 1400px;
            margin: 0 auto;
            padding: 2rem 2rem 0;
        }
        .welcome-hero {
            border-radius: 24px;
            height: 300px;
        }
        .app-header {
            position: relative;
            padding: 0 0 1.5rem 0;
        }
        .priority-section {
            grid-column: span 8;
            margin-bottom: 0;
        }
        .whats-next-section {
            grid-column: span 4;
        }
        /* Fix horizontal scrolling sections for desktop to be grids */
        .priority-scroll-wrapper {
            overflow: visible;
            margin: 0;
            padding: 0;
        }
        .priority-track {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 1.5rem;
            padding: 0;
        }
        .priority-card {
            width: 100%;
            min-height: 160px;
        }

        /* Discover Tab Desktop */
        #discover-header, .discover-sub-nav {
            padding-left: 2rem;
            padding-right: 2rem;
            max-width: 1400px;
            margin: 0 auto;
            width: 100%;
            background: transparent;
            backdrop-filter: none;
        }
        .discover-sub-nav {
            justify-content: flex-start;
            gap: 2rem;
        }
        .discover-sub-nav .nav-item {
            flex: 0 0 auto;
        }
        /* Transform Launcher Row to Grid */
        .launcher-section { grid-column: span 12; }
        .launcher-row-wrapper { overflow: visible; }
        .launcher-row {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
            gap: 1.5rem;
            padding: 0;
        }
        .app-link--recent .icon-wrapper { width: 60px; height: 60px; font-size: 1.5rem; margin-bottom: 0.5rem; }
        .apps-grid {
            grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
            gap: 2rem;
            padding: 0;
        }

        /* Feeds Desktop */
        .feed-container {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 1.5rem;
            padding: 0 2rem 2rem;
            max-width: 1400px;
            margin: 0 auto;
            overflow-y: visible;
            scroll-snap-type: none;
        }
        .feed-slide {
            height: auto;
            aspect-ratio: 4/5;
            padding: 0;
            scroll-snap-align: none;
        }
        .filter-pills-container {
            padding-left: 2rem;
            max-width: 1400px;
            margin: 0 auto;
        }

        /* Study Tab Desktop */
        .study-header { padding: 1rem 2rem; }
        .study-section {
            display: grid;
            grid-template-columns: repeat(12, 1fr);
            gap: 1.5rem;
            padding: 2rem;
            max-width: 1400px;
            margin: 0 auto;
        }
        .library-preview-wrapper { grid-column: span 5; }
        .study-section > .study-section-right { display: contents; } /* Virtual container */
        .compact-trigger { grid-column: span 7; margin-bottom: 0; }
        .guidance-path { grid-column: span 7; grid-row: 2; margin-top: 1.5rem; }
        .observatory-widget { grid-column: span 5; grid-row: 2; margin-top: 1.5rem; height: auto; min-height: 180px; }

        /* Connect Tab Desktop */
        #connect-content .interactive-header { max-width: 1400px; margin: 0 auto; width: 100%; }
        .hub-view { max-width: 1000px; margin: 0 auto; width: 100%; padding-top: 1rem; }
        .messages-list-item {
            padding: 1.5rem;
            transition: transform 0.2s;
        }
        .messages-list-item:hover {
            transform: translateX(5px);
            background-color: rgba(255,255,255,0.05);
        }

        /* Profile Tab Desktop */
        .profile-hero { padding-top: 0; display: flex; align-items: flex-end; height: 350px; }
        .profile-banner { height: 100%; opacity: 0.6; mask-image: linear-gradient(to bottom, black, transparent); }
        .hero-content { max-width: 1400px; width: 100%; margin: 0 auto; padding-bottom: 3rem; }
        .profile-avatar-wrapper { width: 140px; height: 140px; }
        .portal-cards-container {
            grid-column: span 12;
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 1.5rem;
        }
        .settings-group { grid-column: span 12; }

        /* Fullscreen Overlays on Desktop -> Modals */
        .fullscreen-overlay, .library-fullscreen {
            display: flex;
            align-items: center;
            justify-content: center;
            background-color: rgba(0, 0, 0, 0.8);
            clip-path: none !important;
            opacity: 0;
            pointer-events: none;
            transition: opacity 0.3s ease;
        }
        .fullscreen-overlay.is-active, .library-fullscreen.is-expanded {
            opacity: 1;
            pointer-events: auto;
        }
        .overlay-content, #library-fullscreen > div {
            width: 900px;
            height: 85vh;
            background-color: var(--bg-dark);
            border-radius: 24px;
            border: 1px solid var(--border-color);
            box-shadow: 0 25px 50px rgba(0,0,0,0.5);
            overflow: hidden;
            display: flex;
            flex-direction: column;
            position: relative;
        }
        /* Specific adjustment for library inner structure */
        #library-fullscreen > div { background-color: var(--bg-dark); }
        .library-fullscreen .vignette-bg { border-radius: 0 0 24px 24px; }
        .bookshelf-perspective { transform: scale(0.9); transform-origin: center bottom; }

        /* Overlay Headers */
        .overlay-header { background: transparent; padding: 2rem; }
        .overlay-inner-content { padding: 0 2rem 2rem; }
    }
</style>

