.filter-pills-container.expanded { max-height: 100px; opacity: 1; padding: 0.5rem 1rem 1rem; }
.library-filters { padding: 0.5rem 1rem 1rem; }

/* --- BOTTOM NAVIGATION BAR --- */
.navigation-magic { flex-shrink: 0; z-index: 100; position: relative; background: var(--surface-dark); height: var(--nav-height); border-radius: 10px 10px 0 0; }
.navigation-magic nav { display: flex; width: 100%; position: relative; height: 100%; }
.navigation-magic li { position: relative; list-style: none; flex: 1; z-index: 2; height: 100%; }
.navigation-magic a { position: relative; display: flex; justify-content: center; align-items: center; flex-direction: column; width: 100%; text-align: center; font-weight: 500; cursor: pointer; height: 100%; }
.navigation-magic .icon { position: relative; display: block; line-height: 75px; font-size: 1.2em; text-align: center; transition: 0.5s; color: var(--text-secondary-dark); }
.navigation-magic li.active .icon { transform: translateY(-35px); color: var(--accent-teal); }
.navigation-magic .text { position: absolute; color: var(--accent-teal); font-weight: bold; font-size: 0.8em; letter-spacing: 0.05em; transition: 0.5s; opacity: 0; transform: translateY(20px); }
.navigation-magic li.active .text { opacity: 1; transform: translateY(12px); }
.indicator { position: absolute; top: -22.5px; width: 20%; height: 45px; background: transparent; border: 4px solid var(--bg-dark); border-radius: 50%; transition: transform 0.5s cubic-bezier(0.68, -0.55, 0.27, 1.55); z-index: 1; box-shadow: 0px 5px 15px rgba(0,0,0,0.2), 0px 0px 0px 3px var(--accent-teal); }

/* --- DESKTOP / PC ADAPTATION (FIXED) --- */
@media (min-width: 900px) {
    /* 1. LAYOUT & SIDEBAR Z-INDEX FIX */
    .app-container {
        flex-direction: row;
        max-width: none;
        overflow: hidden;
    }
    .navigation-magic {
        order: -1;
        width: 260px;
        height: 100%;
        background: rgba(12, 12, 12, 0.98);
        border-right: 1px solid var(--border-color);
        border-radius: 0;
        display: flex;
        flex-direction: column;
        padding-top: 2rem;
        overflow-y: auto;
        z-index: 500; /* High z-index to ensure clickability */
        position: relative;
    }
    .navigation-magic nav {
        flex-direction: column;
        height: auto;
        gap: 0.5rem;
        padding: 0 1rem;
    }
    .navigation-magic li {
        width: 100%;
        height: 55px;
        flex: 0 0 auto;
        cursor: pointer; /* Ensure pointer cursor */
    }
    .navigation-magic a {
        flex-direction: row;
        justify-content: flex-start;
        padding-left: 1.5rem;
        border-radius: 12px;
        pointer-events: none; /* Let parent li handle click or bubble correctly */
    }
    .navigation-magic li a { pointer-events: auto; } /* Re-enable on anchor */

    .navigation-magic .icon {
        transform: none !important;
        line-height: normal;
        margin-right: 1rem;
        font-size: 1.2rem;
    }
    .navigation-magic .text {
        position: static;
        transform: none !important;
        opacity: 1;
        font-size: 1rem;
    }
    .navigation-magic li.active a {
        background: rgba(66, 215, 184, 0.15);
    }
    .navigation-magic .indicator { display: none; }

    /* 2. MAIN CONTENT & SCROLL FIXES */
    .main-content {
        flex-grow: 1;
        height: 100%;
        overflow: hidden;
