import React, { useState, useEffect, useRef } from 'react';

// --- IndexedDB Caching Helper ---
const db = {
    _db: null,
    async init() {
        return new Promise((resolve, reject) => {
            if (this._db) return resolve();
            const request = indexedDB.open('BookCache', 1);
            request.onupgradeneeded = e => {
                const db = e.target.result;
                if (!db.objectStoreNames.contains('books')) {
                    db.createObjectStore('books', { keyPath: 'path' });
                }
            };
            request.onsuccess = e => { this._db = e.target.result; resolve(); };
            request.onerror = e => reject('IndexedDB error: ' + e.target.errorCode);
        });
    },
    async getBook(path) {
        await this.init();
        return new Promise((resolve) => {
            const tx = this._db.transaction('books', 'readonly');
            const store = tx.objectStore('books');
            const req = store.get(path);
            req.onsuccess = () => resolve(req.result ? req.result.content : null);
            req.onerror = () => resolve(null);
        });
    },
    async saveBook(path, content) {
        await this.init();
        const tx = this._db.transaction('books', 'readwrite');
        tx.objectStore('books').put({ path, content });
    }
};

// --- Book Reader Component ---
