            </header>
            <iframe srcDoc={book.content} style={{ flex: 1, border: 'none', width: '100%', height: '100%' }} sandbox="allow-scripts allow-same-origin"></iframe>
        </div>
    );
};

const Study = () => {
    const [isLibraryOpen, setIsLibraryOpen] = useState(false);
    const [isHeaderExpanded, setIsHeaderExpanded] = useState(false);
    const [books, setBooks] = useState([]);
    const [activeBook, setActiveBook] = useState({ path: null, content: null, title: null, status: 'idle', progress: 0 });
    const wavePathRef = useRef(null);

    useEffect(() => {
        fetch('https://vlzgfaqrnyiqfxxxvtas.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ action: 'list_books' })
        })
        .then(res => res.json())
        .then(data => { if(data.books) setBooks(data.books); })
        .catch(err => console.error(err));
    }, []);

    const openBook = async (book) => {
        setActiveBook({ ...book, status: 'loading', progress: 0 });
        const cachedContent = await db.getBook(book.path);
        if (cachedContent) {
            setActiveBook({ ...book, content: cachedContent, status: 'ready' });
            return;
        }

        try {
            setActiveBook(prev => ({ ...prev, status: 'downloading' }));
            const response = await fetch('https://vlzgfaqrnyiqfxxxvtas.supabase.co/functions/v1/book-reader', {
                method: 'POST',
                headers: {'Content-Type': 'application/json', 'Accept-Encoding': 'gzip'},
                body: JSON.stringify({ action: 'get_book_compressed', book_path: book.path })
            });

            if (!response.ok || !response.body) throw new Error('Download failed');

            const reader = response.body.getReader();
            const totalSize = Number(response.headers.get('Content-Length')) || 0; // May be 0 if chunked
            let receivedLength = 0;
            let chunks = [];

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                chunks.push(value);
                receivedLength += value.length;
                if(totalSize > 0) setActiveBook(prev => ({ ...prev, progress: (receivedLength / totalSize) * 100 }));
            }

            const blob = new Blob(chunks);
            const content = await blob.text();
            await db.saveBook(book.path, content);
            setActiveBook({ ...book, content, status: 'ready' });

        } catch (error) {
            console.error(error);
            setActiveBook({ ...book, status: 'error' });
        }
    };

    const getBookColor = (title) => {
        let hash = 0;
        for (let i = 0; i < title.length; i++) hash = title.charCodeAt(i) + ((hash << 5) - hash);
        return `linear-gradient(135deg, hsl(${Math.abs(hash) % 360}, 50%, 30%), hsl(${(Math.abs(hash) + 40) % 360}, 60%, 15%))`;
    };

