const openBook = async (bookPath) => {
    setLoadingBook(true);
    try {
        const res = await fetch('https://vlzgfaqrnyiqfxxxvtas.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ action: 'get_book_compressed', book_path: bookPath })
        });
        if (!res.ok) throw new Error("Load failed");

        let html = await res.text();

        // DYNAMIC VIEWPORT STRATEGY:
        // 1. Remove hardcoded viewports to prevent conflicts.
        // 2. Inject a script that measures the *actual* content width.
        // 3. Set the viewport width to that content width.
        // This forces the browser to "Zoom Out" to fit the content initially,
        // but 'user-scalable=yes' ensures the user can still pinch-zoom.

        html = html.replace(/<meta\s+name=["']viewport["'][^>]*>/gi, "");

        const smartViewportScript = `
            <script>
                window.addEventListener('load', function() {
                    setTimeout(() => {
                        // Measure the content width (max of body or document)
                        const w = Math.max(
                            document.body.scrollWidth, 
                            document.body.offsetWidth, 
                            document.documentElement.scrollWidth, 
                            800 // Fallback minimum
                        );

                        // Create or update the viewport meta tag
                        let vp = document.querySelector('meta[name="viewport"]');
                        if (!vp) {
                            vp = document.createElement('meta');
                            vp.name = 'viewport';
                            document.head.appendChild(vp);
                        }

                        // Setting width=w tells the browser the page is w pixels wide.
                        // The browser then scales it down to fit the device screen.
                        vp.setAttribute('content', 'width=' + w + ', user-scalable=yes');
                    }, 100);
                });
            </script>
        `;

        if (html.includes("</body>")) {
            html = html.replace("</body>", smartViewportScript + "</body>");
        } else {
            html = html + smartViewportScript;
        }

        const blob = new Blob([html], { type: 'text/html' });
        const url = URL.createObjectURL(blob);
        setActiveBookContent(url);
        setReaderOpen(true);
    } catch (e) {
        console.error("Failed to load book", e);
    } finally {
        setLoadingBook(false);
    }
