const openBook = async (bookPath) => {
    setLoadingBook(true);
    try {
        // 1. SET DESKTOP VIEWPORT
        // We tell the browser: "Treat this screen as if it is 1024px wide".
        // On a mobile device, this forces the browser to ZOOM OUT significantly to fit the content.
        // We also enable 'user-scalable=yes' to allow native pinch-to-zoom.
        const viewport = document.querySelector('meta[name="viewport"]');
        if (viewport) {
            viewport.setAttribute('content', 'width=1024, user-scalable=yes');
        }

        const res = await fetch('https://vlzgfaqrnyiqfxxxvtas.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ action: 'get_book_compressed', book_path: bookPath })
        });
        if (!res.ok) throw new Error("Load failed");

        const rawHtml = await res.text();

        // 2. PARSE HTML & EXTRACT CONTENT
        // Instead of using an iframe (which isolates touch events), we parse the HTML
        // and inject it directly into our page DIV. This ensures touch/pinch events propagate correctly.
        const parser = new DOMParser();
        const doc = parser.parseFromString(rawHtml, 'text/html');

        // Extract styles from the PDF/HTML
        const styles = Array.from(doc.querySelectorAll('style')).map(s => s.outerHTML).join('\n');

        // Extract the body content
        const bodyContent = doc.body.innerHTML;

        setActiveBookContent({ styles, body: bodyContent });
        setReaderOpen(true);
    } catch (e) {
        console.error("Failed to load book", e);
        // Restore mobile viewport on error
        const viewport = document.querySelector('meta[name="viewport"]');
        if (viewport) viewport.setAttribute('content', 'width=device-width, initial-scale=1.0, user-scalable=no');
    } finally {
        setLoadingBook(false);
    }
};

