/* Deep Zoom Reader Styles */
.reader-overlay {
    position: fixed;
    inset: 0;
    z-index: 99999;
    background-color: #2b2b2b;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    touch-action: none;
    animation: readerFadeIn 0.3s ease-out;
}

@keyframes readerFadeIn {
    from { opacity: 0; transform: scale(0.98); }
    to { opacity: 1; transform: scale(1); }
}

.reader-viewport {
    width: 100%;
    height: 100%;
    overflow: hidden;
    cursor: grab;
    position: relative;
    touch-action: none;
}

.reader-viewport:active {
    cursor: grabbing;
}

.reader-world {
    position: absolute;
    top: 0;
    left: 0;
    transform-origin: 0 0;
    background-color: white;
    box-shadow: 0 0 50px rgba(0,0,0,0.5);
    min-width: 1px;
    min-height: 1px;
    will-change: transform;
}

.book-page {
    position: relative;
    overflow: hidden;
    background: white;
    border-bottom: 2px solid #ccc;
}

/* Ensure imported PDF-HTML doesn't overflow */
.book-page > * {
    max-width: 100%;
}

.reader-ui {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 60px;
    background: rgba(43, 43, 43, 0.95);
    color: white;
    z-index: 100000;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 20px;
    border-bottom: 1px solid #444;
    backdrop-filter: blur(5px);
    transition: transform 0.3s ease;
}

.reader-ui.ui-hidden {
    transform: translateY(-100%);
}

.reader-btn {
    background: none;
    border: none;
    color: white;
    font-size: 1.5rem;
    cursor: pointer;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: background 0.2s;
}

.reader-btn:active {
    background: rgba(255,255,255,0.2);
}

.reader-title {
    font-size: 1rem;
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 60%;
}

.reader-loading {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    color: #888;
    text-align: center;
    pointer-events: none;
}

.spinner {
    width: 40px;
    height: 40px;
    border: 4px solid rgba(255,255,255,0.1);
    border-left-color: #42d7b8;
    border-radius: 50%;
    animation: spin 1s linear infinite;
    margin: 0 auto 10px;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

import React, { useEffect, useRef, useState } from 'react';
import './Reader.css';

const MIN_SCALE = 0.05;
const MAX_SCALE = 50;

const DeepZoomReader = ({ book, onClose }) => {
    const viewportRef = useRef(null);
    const worldRef = useRef(null);
    const [loading, setLoading] = useState(true);
    const [uiVisible, setUiVisible] = useState(true);

    // Transformation State (Mutable ref for performance in gesture loops)
    const state = useRef({
        scale: 1,
        panning: false,
        pointX: 0,
        pointY: 0,
        startX: 0,
        startY: 0
    });

    // 1. Fetch and Inject Content
    useEffect(() => {
        const loadContent = async () => {
            try {
                setLoading(true);
                const response = await fetch('https://vlzgfaqrnyiqfxxxvtas.supabase.co/functions/v1/book-reader', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'get_book_compressed', book_path: book.path })
                });

                if (!response.ok) throw new Error('Failed to load book');

                const htmlContent = await response.text();

                // Parse content
                const parser = new DOMParser();
                const doc = parser.parseFromString(htmlContent, 'text/html');

                // Clear world
                if (worldRef.current) {
                    worldRef.current.innerHTML = '';

                    // Inject styles safely
                    const styles = doc.querySelectorAll('style');
                    styles.forEach(style => worldRef.current.appendChild(style));

                    // Inject body content wrapped in a page div
                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'book-page';
                    while (doc.body.firstChild) {
                        pageDiv.appendChild(doc.body.firstChild);
                    }
                    worldRef.current.appendChild(pageDiv);
                }

                // Wait for render then center
                setTimeout(() => resetView(), 100);
            } catch (err) {
                console.error(err);
                alert("Error loading book content");
            } finally {
                setLoading(false);
            }
        };

        if (book) loadContent();
    }, [book]);

    // 2. View Reset Logic
    const resetView = () => {
        if (!viewportRef.current || !worldRef.current) return;
        const vpRect = viewportRef.current.getBoundingClientRect();
        const contentWidth = worldRef.current.scrollWidth || 800;

        const targetScale = (vpRect.width / contentWidth) * 0.95;

        state.current.scale = targetScale;
        state.current.pointX = (vpRect.width - contentWidth * targetScale) / 2;
        state.current.pointY = 60; // Padding for top bar
        updateTransform();
    };

    const updateTransform = () => {
        if (worldRef.current) {
            const { pointX, pointY, scale } = state.current;
            worldRef.current.style.transform = `translate(${pointX}px, ${pointY}px) scale(${scale})`;
        }
    };

    // 3. Gesture Handling (Pointer Events)
    useEffect(() => {
        const viewport = viewportRef.current;
        if (!viewport) return;

        let pointers = [];
        let startDist = 0;
        let startScale = 1;

        const onPointerDown = (e) => {
            e.preventDefault();
            viewport.setPointerCapture(e.pointerId);
            pointers.push(e);

            if (pointers.length === 1) {
                state.current.panning = true;
                state.current.startX = e.clientX - state.current.pointX;
                state.current.startY = e.clientY - state.current.pointY;
            } else if (pointers.length === 2) {
                state.current.panning = false;
                startDist = getDistance(pointers[0], pointers[1]);
                startScale = state.current.scale;
            }
        };

        const onPointerMove = (e) => {
            e.preventDefault();
            const index = pointers.findIndex(p => p.pointerId === e.pointerId);
            if (index !== -1) pointers[index] = e;

            if (pointers.length === 1 && state.current.panning) {
                state.current.pointX = e.clientX - state.current.startX;
                state.current.pointY = e.clientY - state.current.startY;
                updateTransform();
