async function generateAiPatch() {
    const prompt = document.getElementById('ai-prompt-input').value.trim();
    if(!prompt) return alert("Please enter a prompt.");

    const checkedBoxes = document.querySelectorAll('#file-list-container .file-check:checked');
    if(checkedBoxes.length === 0) return alert("Please select at least one file in the Context tab to modify.");

    const filePaths = Array.from(checkedBoxes).map(cb => cb.value);
    const btn = document.querySelector('.ai-controls button');
    const originalText = btn.innerText;
    btn.innerText = "Thinking...";
    btn.disabled = true;

    try {
        const contextPayload = [];
        for (const path of filePaths) {
            if (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
                contextPayload.push({ path: path, content: btoa(window.CURRENT_FILE_CACHE[path].content) });
            } else {
                const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
                const data = await res.json();
                contextPayload.push({ path: path, content: data.content });
            }
        }

        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'generate_ops', user_prompt: prompt, context_files: contextPayload })
        });

        const data = await res.json();

        if(data.operations) {
            document.getElementById('json-input').value = data.operations;
            saveState();
            const editor = document.getElementById('json-input');
            editor.style.outline = "2px solid #d946ef";
            setTimeout(() => editor.style.outline = "none", 500);
        }
    } catch (e) {
        alert("AI Error: " + e.message);
    } finally {
        btn.innerText = originalText;
        btn.disabled = false;
    }
}

    // --- AI OPERATION GENERATOR ---
    if (action === "generate_ops") {
        const { user_prompt, context_files } = payload;
        if (!user_prompt) throw new Error("Prompt required");

        const apiKey = await getGeminiKey();
        if (!apiKey) throw new Error("No AI Key");

        const url = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${apiKey}`;

        const fileContext = context_files.map((f: any) => 
            `FILE: ${f.path}\nCONTENT:\n${f.content ? base64ToText(f.content).substring(0, 3000) : "(Content omitted)"}\n`
        ).join("\n---\n");

        const systemPrompt = `
You are a JSON Patch Generator for a specific IDE engine.
Your goal: Convert the user's Natural Language Request into a JSON Array of Operations.

**AVAILABLE OPERATIONS:**
1. { "file_path": "path/to/file.ext", "action": "replace_block", "find_block": "exact code to replace", "replace_with": "new code" }
2. { "file_path": "...", "action": "insert_after", "anchor": "exact line to insert after", "content": "new code" }
3. { "file_path": "...", "action": "create_file", "content": "full content" }
4. { "file_path": "...", "action": "delete_file" }

**RULES:**
- Return ONLY the raw JSON array. No markdown, no explanations.
- "find_block" and "anchor" must be UNIQUE strings found in the file context.
- Do not use regex. Use exact string matching.
- If the user asks to edit a file not provided in context, guess the path but warn in a comment field.
`;

        const finalPrompt = `
${systemPrompt}

=== CONTEXT FILES ===
${fileContext}

=== USER REQUEST ===
${user_prompt}
`;

        const res = await fetch(url, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                contents: [{ role: "user", parts: [{ text: finalPrompt }] }]
            })
        });

        const data = await res.json();
        let rawText = data.candidates?.[0]?.content?.parts?.[0]?.text || "[]";
        rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();

        return new Response(JSON.stringify({ operations: rawText }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

