    // --- NAVIGATION LOGIC ---
    private fun createBottomNav(): View {
        val dock = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            gravity = Gravity.CENTER
            background = GradientDrawable().apply {
                color = android.content.res.ColorStateList.valueOf(0xCC141414.toInt())
                cornerRadius = 100f
                setStroke(2, COL_BORDER)
            }
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 180).apply {
                gravity = Gravity.BOTTOM
                setMargins(50, 0, 50, 50)
            }
            elevation = 40f
        }

        val tabs = listOf(
            "📊" to { loadDashboard() },
            "⚙️" to { loadSpecs() },
            "🌍" to { loadNetwork() },
            "🧩" to { loadTools() }
        )

        tabs.forEach { (icon, action) ->
            val btn = TextView(this).apply {
                text = icon
                textSize = 24f
                gravity = Gravity.CENTER
                layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.MATCH_PARENT, 1f)
                setOnClickListener {
                    activeTabButton?.alpha = 0.5f
                    alpha = 1.0f
                    activeTabButton = this
                    contentContainer.removeAllViews()
                    // Simple fade animation
                    contentContainer.alpha = 0f
                    contentContainer.animate().alpha(1f).setDuration(300).start()
                    action()
                }
                alpha = 0.5f
            }
            if (icon == "📊") {
                 btn.alpha = 1.0f
                 activeTabButton = btn
            }
            dock.addView(btn)
        }
        return dock
    }

    // --- VIEWS ---

    private fun loadDashboard() {
        // 1. RAM & BATTERY GAUGES
        val gaugeRow = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            weightSum = 2f
        }

        // Memory Logic
        val mem = getMemoryInfo(this)
        val usedMem = mem["used"] ?: 0L
        val totalMem = mem["total"] ?: 1L
        val memPct = ((usedMem.toDouble() / totalMem.toDouble()) * 100).toInt()

        // Battery Logic
        val bat = getBatteryInfo(this)
        val batPct = bat["pct"]?.toInt() ?: 0

        gaugeRow.addView(createGaugeCard("RAM USED", "${usedMem/1024} GB", memPct, COL_PURPLE))
        gaugeRow.addView(createGaugeCard("BATTERY", "$batPct%", batPct, COL_GREEN))

        contentContainer.addView(gaugeRow)

        // 2. STORAGE BAR
        val store = getStorageInfo(this)
        val usedStore = store["used"] ?: 0L
        val totalStore = store["total"] ?: 1L
        val storePct = ((usedStore.toDouble() / totalStore.toDouble()) * 100).toInt()

        contentContainer.addView(createBarCard("INTERNAL STORAGE", "${usedStore}GB / ${totalStore}GB", storePct, COL_CYAN))

        // 3. SYSTEM SUMMARY
        contentContainer.addView(createDetailCard("SYSTEM", mapOf(
            "Android Version" to Build.VERSION.RELEASE,
            "Security Patch" to (if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) Build.VERSION.SECURITY_PATCH else "Unknown"),
            "Kernel" to System.getProperty("os.version").toString()
        )))
    }

    private fun loadSpecs() {
        contentContainer.addView(createDetailCard("PROCESSOR", mapOf(
            "SoC" to Build.BOARD,
            "Hardware" to Build.HARDWARE,
            "Cores" to "${Runtime.getRuntime().availableProcessors()} Cores",
            "ABIs" to Build.SUPPORTED_ABIS.firstOrNull()
        )))

        val dm = resources.displayMetrics
        contentContainer.addView(createDetailCard("DISPLAY", mapOf(
            "Resolution" to "${dm.widthPixels} x ${dm.heightPixels}",
            "Density" to "${dm.densityDpi} DPI",
            "Scale" to "${dm.density}x"
        )))
    }

    private fun loadNetwork() {
        val net = getNetworkInfoMap(this)
        contentContainer.addView(createDetailCard("CONNECTIVITY", net))
    }

    private fun loadTools() {
        val sensors = getSensorList(this)
        contentContainer.addView(createDetailCard("SENSORS (${sensors.size})", sensors.take(8).toMap()))
    }


    // --- UI COMPONENTS ---

    private fun createGlassCard(): LinearLayout {
        return LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            background = GradientDrawable().apply {
                color = android.content.res.ColorStateList.valueOf(COL_GLASS)
                cornerRadius = 40f
                setStroke(2, COL_BORDER)
            }
            setPadding(50, 50, 50, 50)
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT).apply {
                setMargins(0, 0, 0, 30)
            }
        }
    }

    private fun createGaugeCard(title: String, value: String, progress: Int, color: Int): View {
        val card = createGlassCard().apply {
            layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f).apply {
                setMargins(10, 0, 10, 30)
            }
            gravity = Gravity.CENTER
        }

        val titleView = TextView(this).apply {
            text = title
            textSize = 10f
            setTextColor(COL_TEXT_MUTED)
            letterSpacing = 0.1f
            gravity = Gravity.CENTER
        }

        val size = 180 // px
        val gauge = FrameLayout(this).apply {
            layoutParams = LinearLayout.LayoutParams(size, size).apply { setMargins(0, 30, 0, 10) }
        }

        val progressBar = ProgressBar(this, null, android.R.attr.progressBarStyleHorizontal).apply {
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT)
            isIndeterminate = false
            max = 100
            this.progress = progress
            progressDrawable = GradientDrawable().apply {
                shape = GradientDrawable.RING
                useLevel = true
                thicknessRatio = 8f
                setColor(color)
            }
            background = GradientDrawable().apply {
                shape = GradientDrawable.RING
                thicknessRatio = 8f
                setColor(0x33FFFFFF.toInt())
            }
            rotation = -90f
        }

        val valueText = TextView(this).apply {
            text = value
            textSize = 14f
            setTextColor(COL_TEXT_MAIN)
            typeface = android.graphics.Typeface.MONOSPACE
            layoutParams = FrameLayout.LayoutParams(ViewGroup.LayoutParams.WRAP_CONTENT, ViewGroup.LayoutParams.WRAP_CONTENT).apply {
                gravity = Gravity.CENTER
            }
        }

        gauge.addView(progressBar)
        gauge.addView(valueText)
        card.addView(titleView)
        card.addView(gauge)
        return card
    }

    private fun createBarCard(title: String, value: String, progress: Int, color: Int): View {
        val card = createGlassCard()

        val header = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT)
        }
        header.addView(TextView(this).apply {
            text = title
            textSize = 10f
            setTextColor(COL_TEXT_MUTED)
            layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f)
        })
        header.addView(TextView(this).apply {
            text = value
            textSize = 12f
            setTextColor(COL_TEXT_MAIN)
            typeface = android.graphics.Typeface.MONOSPACE
        })

        val barBg = FrameLayout(this).apply {
            layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 15).apply { setMargins(0, 20, 0, 0) }
            background = GradientDrawable().apply {
                setColor(0x33FFFFFF.toInt())
                cornerRadius = 10f
            }
        }
        val barFill = View(this).apply {
            layoutParams = FrameLayout.LayoutParams(0, ViewGroup.LayoutParams.MATCH_PARENT)
            background = GradientDrawable().apply {
                setColor(color)
                cornerRadius = 10f
            }
        }
        // Set width based on pct
        barFill.post { 
            val params = barFill.layoutParams
            params.width = (barBg.width * (progress / 100f)).toInt()
            barFill.layoutParams = params
        }

        barBg.addView(barFill)
        card.addView(header)
        card.addView(barBg)
        return card
    }

    private fun createDetailCard(title: String, data: Map<String, String?>): View {
        val card = createGlassCard()
        card.addView(TextView(this).apply {
            text = title
            textSize = 11f
            setTextColor(COL_CYAN)
            letterSpacing = 0.15f
            setPadding(0, 0, 0, 20)
        })

        data.forEach { (k, v) ->
            val row = LinearLayout(this).apply {
                orientation = LinearLayout.HORIZONTAL
                setPadding(0, 15, 0, 15)
            }
            row.addView(TextView(this).apply {
                text = k
                textSize = 13f
                setTextColor(COL_TEXT_MUTED)
                layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f)
            })
            row.addView(TextView(this).apply {
                text = v ?: "N/A"
                textSize = 13f
                setTextColor(COL_TEXT_MAIN)
                typeface = android.graphics.Typeface.MONOSPACE
                gravity = Gravity.END
            })
            card.addView(row)
            // Divider
            card.addView(View(this).apply {
                layoutParams = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, 1)
                setBackgroundColor(0x1AFFFFFF.toInt())
            })
        }
        return card
    }

    // --- DATA HELPERS ---

    private fun getMemoryInfo(ctx: Context): Map<String, Long> {
        val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
        val memInfo = android.app.ActivityManager.MemoryInfo()
        actManager.getMemoryInfo(memInfo)
        val total = memInfo.totalMem / (1024 * 1024)
        val avail = memInfo.availMem / (1024 * 1024)
        return mapOf("total" to total, "used" to (total - avail))
    }

    private fun getBatteryInfo(ctx: Context): Map<String, Float> {
        val batt = ctx.registerReceiver(null, android.content.IntentFilter(android.content.Intent.ACTION_BATTERY_CHANGED))
        val level = batt?.getIntExtra(android.os.BatteryManager.EXTRA_LEVEL, 0) ?: 0
        val scale = batt?.getIntExtra(android.os.BatteryManager.EXTRA_SCALE, 100) ?: 100
        return mapOf("pct" to (level * 100 / scale.toFloat()))
    }

    private fun getStorageInfo(ctx: Context): Map<String, Long> {
        val stat = android.os.StatFs(android.os.Environment.getDataDirectory().path)
        val total = (stat.blockCountLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
        val free = (stat.availableBlocksLong * stat.blockSizeLong) / (1024 * 1024 * 1024)
        return mapOf("total" to total, "used" to (total - free))
    }

    private fun getNetworkInfoMap(ctx: Context): Map<String, String> {
        val cm = ctx.getSystemService(Context.CONNECTIVITY_SERVICE) as android.net.ConnectivityManager
        val net = cm.activeNetwork
        val caps = cm.getNetworkCapabilities(net)
        val connected = net != null

        return mapOf(
            "Status" to if(connected) "Online" else "Offline",
            "Type" to if(caps?.hasTransport(android.net.NetworkCapabilities.TRANSPORT_WIFI) == true) "WiFi" else "Cellular",
            "Downlink" to "${(caps?.linkDownstreamBandwidthKbps ?: 0)/1000} Mbps"
        )
    }

    private fun getSensorList(ctx: Context): List<Pair<String, String>> {
        val sm = ctx.getSystemService(Context.SENSOR_SERVICE) as android.hardware.SensorManager
        return sm.getSensorList(android.hardware.Sensor.TYPE_ALL).map {
            it.name to "${it.vendor}"
        }
    }
}

