                    row.addView(info)
                    row.addView(TextView(ctx).apply {
                        text = formatDuration(usage.totalTimeInForeground)
                        textSize=11f; setTextColor(0xFF94A1B2.toInt()); typeface=Typeface.MONOSPACE; setPadding(20,0,0,0)
