// --- AI REGISTRY & ROUTING ---
interface AIProvider {
  name: string;
  baseUrl: string;
  model: string;
  apiKeyEnv: string;
  type: 'openai' | 'google';
}

interface AIConfig {
  providers: Record<string, AIProvider>;
  roles: {
    chat: string;
    architect: string;
    fast_fix: string;
    analyst: string;
  };
}

const DEFAULT_AI_CONFIG: AIConfig = {
