package com.example.myandroid

import android.content.Context
import android.os.Environment
import android.os.StatFs
import org.json.JSONArray
import org.json.JSONObject
import java.io.File

object StorageManager {

    fun getStats(): Pair<String, Int> {
        val path = Environment.getExternalStorageDirectory()
        val stat = StatFs(path.path)
        val blockSize = stat.blockSizeLong
        val totalBlocks = stat.blockCountLong
        val availableBlocks = stat.availableBlocksLong

        val total = totalBlocks * blockSize
        val free = availableBlocks * blockSize
        val used = total - free

        val pct = ((used.toFloat() / total.toFloat()) * 100).toInt()
        return Pair(formatSize(used) + " / " + formatSize(total), pct)
    }

    fun generateSkeleton(ctx: Context): JSONObject {
        val root = Environment.getExternalStorageDirectory()
        val json = JSONObject()
        json.put("root", root.absolutePath)
        json.put("tree", scanDirectory(root, 0))

        // Save to cache immediately so SyncWorker can pick it up without re-scanning
        ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE)
            .edit()
            .putString("cached_storage_map", json.toString())
            .apply()

        return json
    }

    private fun scanDirectory(dir: File, depth: Int): JSONArray {
        val list = JSONArray()
        // SAFETY: Limit recursion depth to 4 levels to avoid huge JSON
        if (depth > 4) return list

        val files = dir.listFiles()
        if (files != null) {
            // SAFETY: Limit items per folder to 200 to prevent OOM
            var count = 0
            for (file in files) {
                if (count > 200) break

                val item = JSONObject()
                item.put("n", file.name)
                item.put("s", formatSize(file.length()))

                if (file.isDirectory) {
                    item.put("type", "folder")
                    item.put("contents", scanDirectory(file, depth + 1))
                } else {
                    item.put("type", "file")
                }
                list.put(item)
                count++
            }
        }
        return list
    }

    private fun formatSize(size: Long): String {
        val kb = size / 1024
        val mb = kb / 1024
        val gb = mb / 1024
        return when {
            gb > 0 -> "$gb GB"
            mb > 0 -> "$mb MB"
            kb > 0 -> "$kb KB"
            else -> "$size B"
        }
    }
}

